import{_ as s,c as a,o as n,O as l}from"./chunks/framework.5d9d2abb.js";const A=JSON.parse('{"title":"闭包的理解与应用","description":"","frontmatter":{},"headers":[],"relativePath":"articles/闭包.md"}'),o={name:"articles/闭包.md"},e=l(`<h1 id="闭包的理解与应用" tabindex="-1">闭包的理解与应用 <a class="header-anchor" href="#闭包的理解与应用" aria-label="Permalink to &quot;闭包的理解与应用&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><ul><li><strong>Closure (computer programming), an abstraction binding a function to its scope（摘自wiki）</strong></li><li>闭包（Closure），又称为词法闭包（Lexical Closure）或函数闭包（function closure）。</li><li>是在支持头等函数的编程语言中，实习词法绑定的一种技术。</li><li>闭包在实现上是一个结构体，它存储了一个函数和一个关联环境</li><li>闭包跟函数最大的区别在于当捕捉闭包的时候，它的自由变量会在捕捉是被确定，这样即使脱离了捕捉时的-上下文，它也能照常运行。</li></ul><p>这样看还是非常的晦涩难懂，所以我们逐步分析理解。先用一个案例来表现闭包：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">var name = &quot;foo&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">function foo(){</span></span>
<span class="line"><span style="color:#A6ACCD;">	var message = &quot;Hello World&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">  	console.log(message,name);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><p>如果学习过c、c++等语言的读者就会发现，在函数中要想使用函数之外定义的变量，必须在调用时将以实参的形式传入函数。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">var name = &quot;foo&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">function foo(name){</span></span>
<span class="line"><span style="color:#A6ACCD;">	var message = &quot;Hello World&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">  	console.log(message,name);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><p><strong>这就是js不同之处，也就是闭包起到了作用</strong></p><ul><li>在JavaScript中，每当创建一个函数，闭包就会在函数创建的同时被创建出来。</li><li>闭包可以在一个内层函数中访问到其外层函数的作用域。</li></ul><p><strong>通俗的说，一个函数如果它可以访问外层作用域的自由变量，那么这个函数与其作用域就是一个闭包。</strong></p><p>##基础原理解析 这一部分笔者想要用自己的理解，来帮助大家了解闭包。甚至这一部分的理解，也可以引申到原型链。 <strong>首先来了解两个概念GO和AO</strong></p><ul><li>GO(Clobal Object)):其包含全局执行的上下文内容。</li><li>AO(Activation Object ):其包含了函数执行期的上下文内容。</li></ul><p>AO是一个即时的存储容器，函数执行完毕以后，AO是要销毁的。（但是有一种情况例外，那就是闭包）</p>`,13),t=[e];function p(i,c,r,u,d,C){return n(),a("div",null,t)}const g=s(o,[["render",p]]);export{A as __pageData,g as default};
